import { useState } from 'react';
import styles from './AuthForm.module.css';

export function AuthForm({ onSuccess }) {
  const [mode, setMode] = useState('login');
  const [form, setForm] = useState({ email: '', password: '', name: '' });
  const [errors, setErrors] = useState({});
  const [globalError, setGlobalError] = useState('');
  const [loading, setLoading] = useState(false);

  const validate = () => {
    const e = {};
    if (!form.email.match(/^[^@]+@[^@]+\.[^@]+$/)) e.email = 'Invalid email';
    if (form.password.length < 8) e.password = 'Min. 8 characters';
    if (mode === 'register' && !form.name.trim()) e.name = 'Name is required';
    return e;
  };

  const handleSubmit = async (ev) => {
    ev.preventDefault();
    const errs = validate();
    if (Object.keys(errs).length) { setErrors(errs); return; }
    setErrors({});
    setGlobalError('');
    setLoading(true);
    // ── Replace with your real API call ───────────────────────────
    await new Promise(r => setTimeout(r, 900));
    // const res = await fetch('/api/auth/' + mode, { method: 'POST', ... });
    // ──────────────────────────────────────────────────────────────
    setLoading(false);
    onSuccess?.({ email: form.email, name: form.name });
  };

  const set = (k) => (ev) => setForm(p => ({ ...p, [k]: ev.target.value }));

  return (
    <div className={styles.wrap}>
      <div className={styles.card}>
        <div className={styles.logo}>
          <svg width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
            <rect x="3" y="11" width="18" height="11" rx="2" />
            <path d="M7 11V7a5 5 0 0 1 10 0v4" />
          </svg>
        </div>
        <h2 className={styles.title}>
          {mode === 'login' ? 'Log in' : 'Create account'}
        </h2>
        <p className={styles.sub}>
          {mode === 'login' ? 'Welcome back' : 'Start for free today'}
        </p>

        <form onSubmit={handleSubmit} noValidate>
          {mode === 'register' && (
            <div className={styles.field}>
              <label className={styles.label}>Name</label>
              <input className={styles.input} type="text" value={form.name} onChange={set('name')} placeholder="Jane Smith" autoFocus />
              {errors.name && <span className={styles.err}>{errors.name}</span>}
            </div>
          )}

          <div className={styles.field}>
            <label className={styles.label}>Email</label>
            <input className={styles.input} type="email" value={form.email} onChange={set('email')} placeholder="jane@example.com" />
            {errors.email && <span className={styles.err}>{errors.email}</span>}
          </div>

          <div className={styles.field}>
            <label className={styles.label}>Password</label>
            <input className={styles.input} type="password" value={form.password} onChange={set('password')} placeholder="••••••••" />
            {errors.password && <span className={styles.err}>{errors.password}</span>}
          </div>

          {globalError && <p className={styles.globalErr}>{globalError}</p>}

          <button className={styles.submit} type="submit" disabled={loading}>
            {loading
              ? <span className={styles.spinner} />
              : (mode === 'login' ? 'Log in' : 'Create account')}
          </button>
        </form>

        <p className={styles.toggle}>
          {mode === 'login' ? "Don't have an account? " : 'Already have an account? '}
          <button className={styles.toggleBtn} onClick={() => { setMode(m => m === 'login' ? 'register' : 'login'); setErrors({}); setGlobalError(''); }}>
            {mode === 'login' ? 'Sign up' : 'Log in'}
          </button>
        </p>
      </div>
    </div>
  );
}

.wrap {
  min-height: 100vh;
  display: flex;
  align-items: center;
  justify-content: center;
  background: #f9f9fb;
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', system-ui, sans-serif;
  padding: 24px;
}

.card {
  width: 100%;
  max-width: 380px;
  background: #fff;
  border: 1px solid #e4e4e7;
  border-radius: 14px;
  padding: 32px 28px 24px;
}

.logo {
  width: 44px;
  height: 44px;
  border-radius: 10px;
  background: rgba(99,102,241,0.08);
  border: 1px solid rgba(99,102,241,0.2);
  display: flex;
  align-items: center;
  justify-content: center;
  color: #6366f1;
  margin-bottom: 18px;
}

.title {
  margin: 0 0 4px;
  font-size: 20px;
  font-weight: 700;
  color: #18181b;
  letter-spacing: -0.02em;
}

.sub {
  margin: 0 0 24px;
  font-size: 13px;
  color: #71717a;
}

.field {
  display: flex;
  flex-direction: column;
  gap: 5px;
  margin-bottom: 14px;
}

.label {
  font-size: 12.5px;
  font-weight: 500;
  color: #3f3f46;
}

.input {
  padding: 9px 12px;
  border: 1px solid #e4e4e7;
  border-radius: 8px;
  font-size: 13.5px;
  color: #18181b;
  background: #fff;
  outline: none;
  transition: border-color 0.12s, box-shadow 0.12s;
}
.input:focus {
  border-color: #6366f1;
  box-shadow: 0 0 0 3px rgba(99,102,241,0.1);
}
.input::placeholder { color: #b4b4bb; }

.err { font-size: 11.5px; color: #ef4444; }

.globalErr {
  margin: 0 0 14px;
  padding: 9px 12px;
  background: #fef2f2;
  border: 1px solid #fecaca;
  border-radius: 8px;
  font-size: 12.5px;
  color: #dc2626;
}

.submit {
  width: 100%;
  padding: 10px;
  margin-top: 4px;
  background: #6366f1;
  color: #fff;
  font-size: 13.5px;
  font-weight: 600;
  border: none;
  border-radius: 8px;
  cursor: pointer;
  transition: opacity 0.12s;
  display: flex;
  align-items: center;
  justify-content: center;
  height: 40px;
}
.submit:hover:not(:disabled) { opacity: 0.88; }
.submit:disabled { opacity: 0.5; cursor: not-allowed; }

.spinner {
  width: 16px;
  height: 16px;
  border: 2px solid rgba(255,255,255,0.3);
  border-top-color: #fff;
  border-radius: 50%;
  animation: spin 0.7s linear infinite;
}
@keyframes spin { to { transform: rotate(360deg); } }

.toggle {
  margin: 18px 0 0;
  text-align: center;
  font-size: 12.5px;
  color: #71717a;
}

.toggleBtn {
  background: none;
  border: none;
  color: #6366f1;
  font-size: 12.5px;
  font-weight: 600;
  cursor: pointer;
  padding: 0;
}
.toggleBtn:hover { text-decoration: underline; }

import { useState, useCallback } from 'react';

// Production hook — replace endpoint and token logic per project
export function useAuth() {
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  const request = async (path, body) => {
    setLoading(true);
    setError(null);
    try {
      const res = await fetch(`/api/auth/${path}`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(body),
      });
      const data = await res.json();
      if (!res.ok) { setError(data.message || 'Error'); return null; }
      if (data.token) localStorage.setItem('token', data.token);
      return data;
    } catch {
      setError('Network error');
      return null;
    } finally {
      setLoading(false);
    }
  };

  const login    = useCallback((email, password) => request('login',    { email, password }),   []);
  const register = useCallback((email, password, name) => request('register', { email, password, name }), []);
  const logout   = useCallback(() => { localStorage.removeItem('token'); }, []);

  return { login, register, logout, loading, error };
}
